import type { PopoverProps } from ':components/Popover';
import type { TooltipProps } from ':components/Tooltip';
import type { HTMLAttributes, ReactElement, Ref } from 'react';
import { TestComponentProps } from 'src/types/test-component';
export type TypographyVariant = 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6' | 'body1' | 'body2' | 'body3' | 'subtitle1' | 'subtitle2' | 'subtitle3' | 'caption' | 'overline' | 'productName' | 'nativeLink' | 'routedLink' | 'contextualLink';
export type TypographyProps = TypographyBaseProps | NativeLink | RoutedLink | ContextualLink;
export interface TypographyBaseProps extends HTMLAttributes<HTMLSpanElement>, TestComponentProps {
    /**
     * Тип компонента.
     */
    variant?: TypographyVariant;
    /**
     * Обрезать непоместившийся текст троеточием.
     */
    ellipsis?: boolean;
    /**
     * Сделать текст неактивным (применяет цвет --color-text-inactive).
     */
    inactive?: boolean;
    /**
     * Ссылка на DOM-элемент.
     */
    ref?: Ref<HTMLElement>;
}
export interface LinkBase {
    linkState?: 'enabled' | 'disabled' | 'visited';
}
export interface NativeLink extends TypographyBaseProps, LinkBase {
    variant: 'nativeLink';
    href?: string;
}
export interface RoutedLink extends TypographyBaseProps, LinkBase {
    variant: 'routedLink';
    routingComponent: ReactElement;
}
export interface ContextualLink extends TypographyBaseProps {
    variant: 'contextualLink';
    linkState?: 'enabled' | 'disabled';
    onHoverElement?: ReactElement<TooltipProps> | ReactElement<PopoverProps>;
}
